void p005_intersperse(const int *numbers, int numbers_size, int delimeter,
         int *out)
/*@ With l outl
    Require 0 <= numbers_size && numbers_size < INT_MAX &&
            IntArray::full(numbers, numbers_size, l) *
            IntArray::undef_full(out, 2 * numbers_size - 1)
    Ensure IntArray::full(numbers, numbers_size, l) *
           IntArray::full(out, 2 * numbers_size - 1 ,outl)
*/
{
    int k = 0;
    if (numbers_size == 0) {
        return;
    }

    out[k] = numbers[0];
    k = k + 1;

    int i;

    /*@ Inv Assert
        exists prefix,
            1 <= i && i <= numbers_size@pre &&
            0 <= numbers_size@pre &&
            numbers_size@pre < INT_MAX &&
            k == 2 * i - 1 &&
            numbers == numbers@pre &&
            numbers_size == numbers_size@pre &&
            delimeter == delimeter@pre &&
            out == out@pre &&
            Zlength(prefix) == k &&
            (forall (j: Z), (0 <= j && j < i) =>
                prefix[2 * j] == l[j]) &&
            (forall (j: Z), (0 <= j && j + 1 < i) =>
                prefix[2 * j + 1] == delimeter) &&
            IntArray::full(numbers, numbers_size@pre, l) *
            IntArray::seg(out@pre, 0, k, prefix) *
            IntArray::undef_seg(out@pre, k, 2 * numbers_size@pre - 1)
    */
    for (i = 1; i < numbers_size; i++) {
        out[k] = delimeter;
        k = k + 1;
        out[k] = numbers[i];
        k = k + 1;
    }

}

